	// Early exit: if v is less than or equal to the first upper bound, return 0
	if v <= h.upperBounds[0] {
		return 0
	}

	// Early exit: if v is greater than the last upper bound, return len(h.upperBounds)
	if v > h.upperBounds[n-1] {
